// Timestamp Token for replay protection
class TimestampToken {
    private final Instant created;
    private final Instant expires;
    private final String messageId;

    public TimestampToken(Instant created, Instant expires, String messageId) {
        this.created = created;
        this.expires = expires;
        this.messageId = messageId;
    }

    public Instant getCreated() { return created; }
    public Instant getExpires() { return expires; }
    public String getMessageId() { return messageId; }

    public boolean isExpired() {
        return Instant.now().isAfter(expires);
    }

    public boolean isValid(Duration maxAge) {
        Instant now = Instant.now();
        if (now.isAfter(expires)) return false;
        if (Duration.between(created, now).abs().compareTo(maxAge) > 0) return false;
        if (created.isAfter(now.plus(Duration.ofMinutes(5)))) return false;
        return true;
    }
}

// Replay Attack Cache
class ReplayProtectionCache {
    private static final ReplayProtectionCache INSTANCE = new ReplayProtectionCache();
    private final ConcurrentHashMap<String, Instant> processedMessages = new ConcurrentHashMap<>();
    private final Duration cacheExpiry = Duration.ofMinutes(10);

    private ReplayProtectionCache() {
        Timer cleanupTimer = new Timer(true);
        cleanupTimer.scheduleAtFixedRate(new TimerTask() {
            @Override
            public void run() {
                cleanupExpiredEntries();
            }
        }, 60000, 60000);
    }

    public static ReplayProtectionCache getInstance() { return INSTANCE; }

    public boolean isReplay(String messageId) {
        if (messageId == null || messageId.isEmpty()) return true;
        Instant previous = processedMessages.putIfAbsent(messageId, Instant.now());
        return previous != null;
    }

    private void cleanupExpiredEntries() {
        Instant cutoff = Instant.now().minus(cacheExpiry);
        processedMessages.entrySet().removeIf(entry -> entry.getValue().isBefore(cutoff));
    }
}

// WS-Security SOAP Handler
class WsSecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final Duration MAX_MESSAGE_AGE = Duration.ofMinutes(5);
    private static final Duration DEFAULT_EXPIRY = Duration.ofMinutes(5);

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (isOutbound) {
            return addSecurityHeader(context);
        } else {
            return validateSecurityHeader(context);
        }
    }

    private boolean addSecurityHeader(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                header = envelope.addHeader();
            }

            SOAPHeaderElement securityElement = header.addHeaderElement(
                    new QName(WSS_NS, "Security", "wsse"));
            securityElement.setMustUnderstand(true);

            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);

            String messageId = UUID.randomUUID().toString();
            timestampElement.addAttribute(new QName(WSU_NS, "Id", "wsu"), "TS-" + messageId);

            Instant now = Instant.now();
            Instant expiry = now.plus(DEFAULT_EXPIRY);

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(DateTimeFormatter.ISO_INSTANT.format(now));

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(DateTimeFormatter.ISO_INSTANT.format(expiry));

            message.saveChanges();
            System.out.println("[WS-Security] Added timestamp token to outbound message: Created=" + now + ", Expires=" + expiry);
            return true;
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error adding security header: " + e.getMessage());
            return false;
        }
    }

    private boolean validateSecurityHeader(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                System.err.println("[WS-Security] No SOAP header found - rejecting message");
                generateSOAPFault(context, "Missing WS-Security header");
                return false;
            }

            TimestampToken token = extractTimestampToken(header);

            if (token == null) {
                System.err.println("[WS-Security] No timestamp token found in Security header");
                generateSOAPFault(context, "Missing timestamp token in WS-Security header");
                return false;
            }

            if (!token.isValid(MAX_MESSAGE_AGE)) {
                System.err.println("[WS-Security] Timestamp token is invalid or expired: Created=" +
                        token.getCreated() + ", Expires=" + token.getExpires());
                generateSOAPFault(context, "Timestamp token is expired or invalid");
                return false;
            }

            if (ReplayProtectionCache.getInstance().isReplay(token.getMessageId())) {
                System.err.println("[WS-Security] Replay attack detected for message: " + token.getMessageId());
                generateSOAPFault(context, "Replay attack detected - message already processed");
                return false;
            }

            System.out.println("[WS-Security] Timestamp validation successful: MessageId=" +
                    token.getMessageId() + ", Created=" + token.getCreated() + ", Expires=" + token.getExpires());
            return true;
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error validating security header: " + e.getMessage());
            return false;
        }
    }

    private TimestampToken extractTimestampToken(SOAPHeader header) throws SOAPException {
        Iterator<?> securityIterator = header.getChildElements(new QName(WSS_NS, "Security"));

        if (!securityIterator.hasNext()) {
            // Try without namespace for testing flexibility
            securityIterator = header.getChildElements(new QName("Security"));
        }

        if (!securityIterator.hasNext()) {
            return null;
        }

        SOAPElement securityElement = (SOAPElement) securityIterator.next();
        Iterator<?> timestampIterator = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));

        if (!timestampIterator.hasNext()) {
            timestampIterator = securityElement.getChildElements(new QName("Timestamp"));
        }

        if (!timestampIterator.hasNext()) {
            return null;
        }

        SOAPElement timestampElement = (SOAPElement) timestampIterator.next();

        String messageId = timestampElement.getAttribute("wsu:Id");
        if (messageId == null || messageId.isEmpty()) {
            messageId = timestampElement.getAttributeValue(new QName(WSU_NS, "Id"));
        }
        if (messageId == null || messageId.isEmpty()) {
            messageId = UUID.randomUUID().toString();
        }

        String createdStr = null;
        String expiresStr = null;

        Iterator<?> createdIterator = timestampElement.getChildElements(new QName(WSU_NS, "Created"));
        if (!createdIterator.hasNext()) {
            createdIterator = timestampElement.getChildElements(new QName("Created"));
        }
        if (createdIterator.hasNext()) {
            createdStr = ((SOAPElement) createdIterator.next()).getTextContent();
        }

        Iterator<?> expiresIterator = timestampElement.getChildElements(new QName(WSU_NS, "Expires"));
        if (!expiresIterator.hasNext()) {
            expiresIterator = timestampElement.getChildElements(new QName("Expires"));
        }
        if (expiresIterator.hasNext()) {
            expiresStr = ((SOAPElement) expiresIterator.next()).getTextContent();
        }

        if (createdStr == null || expiresStr == null) {
            System.err.println("[WS-Security] Timestamp missing Created or Expires element");
            return null;
        }

        try {
            Instant created = Instant.parse(createdStr);
            Instant expires = Instant.parse(expiresStr);

            System.out.println("[WS-Security] Extracted timestamp - MessageId: " + messageId +
                    ", Created: " + created + ", Expires: " + expires);

            return new TimestampToken(created, expires, messageId);
        } catch (Exception e) {
            System.err.println("[WS-Security] Error parsing timestamp values: " + e.getMessage());
            return null;
        }
    }

    private void generateSOAPFault(SOAPMessageContext context, String faultMessage) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
            body.removeContents();
            SOAPFault fault = body.addFault();
            fault.setFaultCode("wsse:InvalidSecurityToken");
            fault.setFaultString(faultMessage);
            message.saveChanges();
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error generating SOAP fault: " + e.getMessage());
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        System.err.println("[WS-Security] Handling SOAP fault");
        try {
            SOAPMessage message = context.getMessage();
            ByteArrayOutputStream out = new ByteArrayOutputStream();
            message.writeTo(out);
            System.err.println("[WS-Security] Fault message: " + out.toString());
        } catch (Exception e) {
            System.err.println("[WS-Security] Error logging fault: " + e.getMessage());
        }
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

// Payment Validation Service
class PaymentValidator {

    public static String validate(PaymentRequest request) {
        if (request == null) {
            return "Payment request is null";
        }
        if (request.getTransactionId() == null || request.getTransactionId().trim().isEmpty()) {
            return "Transaction ID is required";
        }
        if (request.getCardNumber() == null || request.getCardNumber().trim().isEmpty()) {
            return "Card number is required";
        }
        if (!isValidCardNumber(request.getCardNumber())) {
            return "Invalid card number format";
        }
        if (request.getCardHolder() == null || request.getCardHolder().trim().isEmpty()) {
            return "Card holder name is required";
        }
        if (request.getAmount() <= 0) {
            return "Amount must be greater than zero";
        }
        if (request.getAmount() > 1000000) {
            return "Amount exceeds maximum limit";
        }
        if (request.getCurrency() == null || request.getCurrency().trim().isEmpty()) {
            return "Currency is required";
        }
        if (!isValidCurrency(request.getCurrency())) {
            return "Invalid currency code";
        }
        if (request.getMerchantId() == null || request.getMerchantId().trim().isEmpty()) {
            return "Merchant ID is required";
        }
        return null;
    }

    private static boolean isValidCardNumber(String cardNumber) {
        String cleaned = cardNumber.replaceAll("[\\s-]", "");
        if (cleaned.length() < 13 || cleaned.length() > 19) return false;
        if (!cleaned.matches("\\d+")) return false;
        return luhnCheck(cleaned);
    }

    private static boolean luhnCheck(String number) {
        int sum = 0;
        boolean alternate = false;
        for (int i = number.length() - 1; i >= 0; i--) {
            int digit = Character.getNumericValue(number.charAt(i));
            if (alternate) {
                digit *= 2;
                if (digit > 9) digit -= 9;
            }
            sum += digit;
            alternate = !alternate;
        }
        return sum % 10 == 0;
    }

    private static boolean isValidCurrency(String currency) {
        Set<String> validCurrencies = new HashSet<>(Arrays.asList(
                "USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF", "CNY", "INR", "BRL"
        ));
        return validCurrencies.contains(currency.toUpperCase());
    }

    public static String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) return "****";
        String cleaned = cardNumber.replaceAll("[\\s-]", "");
        return "****-****-****-" + cleaned.substring(cleaned.length() - 4);
    }
}

// Payment Processing Service Implementation
@WebService(
        name = "PaymentProcessingService",
        serviceName = "PaymentGatewayService",
        portName = "PaymentProcessingPort",
        targetNamespace = "http://gateway.payment.com/ws"
)
class PaymentProcessingServiceImpl {

    @Resource
    private WebServiceContext wsContext;

    private static final Map<String, String> processedTransactions = new ConcurrentHashMap<>();

    @WebMethod(operationName = "processPayment")
    public PaymentResponse processPayment(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "cardNumber") String cardNumber,
            @WebParam(name = "cardHolder") String cardHolder,
            @WebParam(name = "amount") double amount,
            @WebParam(name = "currency") String currency,
            @WebParam(name = "merchantId") String merchantId,
            @WebParam(name = "description") String description) {

        System.out.println("\n[Payment Gateway] Processing payment request...");
        System.out.println("[Payment Gateway] Transaction ID: " + transactionId);
        System.out.println("[Payment Gateway] Card: " + PaymentValidator.maskCardNumber(cardNumber));
        System.out.println("[Payment Gateway] Amount: " + amount + " " + currency);
        System.out.println("[Payment Gateway] Merchant: " + merchantId);

        PaymentRequest request = new PaymentRequest(
                transactionId, cardNumber, cardHolder, amount, currency, merchantId, description);

        String validationError = PaymentValidator.validate(request);
        if (validationError != null) {
            System.out.println("[Payment Gateway] Validation failed: " + validationError);
            return new PaymentResponse(
                    transactionId,
                    "DECLINED",
                    validationError,
                    null,
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        // Check for duplicate transaction
        if (processedTransactions.containsKey(transactionId)) {
            System.out.println("[Payment Gateway] Duplicate transaction detected: " + transactionId);
            return new PaymentResponse(
                    transactionId,
                    "DUPLICATE",
                    "Transaction already processed",
                    processedTransactions.get(transactionId),
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        // Simulate payment processing
        PaymentResponse response = simulatePaymentProcessing(request);

        if ("APPROVED".equals(response.getStatus())) {
            processedTransactions.put(transactionId, response.getAuthorizationCode());
        }

        System.out.println("[Payment Gateway] Response: " + response);
        return response;
    }

    @WebMethod(operationName = "refundPayment")
    public PaymentResponse refundPayment(
            @WebParam(name = "originalTransactionId") String originalTransactionId,
            @WebParam(name = "refundAmount") double refundAmount,
            @WebParam(name = "reason") String reason) {

        System.out.println("\n[Payment Gateway] Processing refund request...");
        System.out.println("[Payment Gateway] Original Transaction: " + originalTransactionId);
        System.out.println("[Payment Gateway] Refund Amount: " + refundAmount);

        if (!processedTransactions.containsKey(originalTransactionId)) {
            return new PaymentResponse(
                    originalTransactionId,
                    "DECLINED",
                    "Original transaction not found",
                    null,
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        if (refundAmount <= 0) {
            return new PaymentResponse(
                    originalTransactionId,
                    "DECLINED",
                    "Invalid refund amount",
                    null,
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        String refundAuthCode = "RF-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();

        return new PaymentResponse(
                originalTransactionId,
                "REFUNDED",
                "Refund processed successfully. Reason: " + reason,
                refundAuthCode,
                DateTimeFormatter.ISO_INSTANT.format(Instant.now())
        );
    }

    @WebMethod(operationName = "checkTransactionStatus")
    public PaymentResponse checkTransactionStatus(
            @WebParam(name = "transactionId") String transactionId) {

        System.out.println("\n[Payment Gateway] Checking transaction status: " + transactionId);

        if (processedTransactions.containsKey(transactionId)) {
            return new PaymentResponse(
                    transactionId,
                    "FOUND",
                    "Transaction was processed successfully",
                    processedTransactions.get(transactionId),
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        return new PaymentResponse(
                transactionId,
                "NOT_FOUND",
                "Transaction not found in system",
                null,
                DateTimeFormatter.ISO_INSTANT.format(Instant.now())
        );
    }

    private PaymentResponse simulatePaymentProcessing(PaymentRequest request) {
        try {
            Thread.sleep(100); // Simulate processing delay
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }

        String cardPrefix = request.getCardNumber().replaceAll("[\\s-]", "").substring(0, 1);

        // Simulate different processing scenarios
        if (request.getAmount() > 500000) {
            return new PaymentResponse(
                    request.getTransactionId(),
                    "DECLINED",
                    "Amount exceeds single transaction limit",
                    null,
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        if (request.getCardNumber().replaceAll("[\\s-]", "").endsWith("0000")) {
            return new PaymentResponse(
                    request.getTransactionId(),
                    "DECLINED",
                    "Card declined by issuing bank",
                    null,
                    DateTimeFormatter.ISO_INSTANT.format(Instant.now())
            );
        }

        String authCode = "AUTH-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();

        return new PaymentResponse(
                request.getTransactionId(),
                "APPROVED",
                "Payment processed successfully",
                authCode,
                DateTimeFormatter.ISO_INSTANT.format(Instant.now())
        );
    }
}

// Custom Handler Resolver
class PaymentHandlerResolver implements HandlerResolver {
    @Override
    public List<Handler> getHandlerChain(PortInfo portInfo) {
        List<Handler> handlerChain = new ArrayList<>();
        handlerChain.add(new WsSecurityHandler());
        return handlerChain;
    }
}

