    private static SOAPMessage createPaymentSOAPRequest(String txnId, String cardNumber,
            String cardHolder, double amount, String currency, String merchantId, String description)
            throws Exception {

        MessageFactory messageFactory = MessageFactory.newInstance();
        SOAPMessage soapMessage = messageFactory.createMessage();
        SOAPPart soapPart = soapMessage.getSOAPPart();
        SOAPEnvelope envelope = soapPart.getEnvelope();

        String targetNs = "http://gateway.payment.com/ws";
        envelope.addNamespaceDeclaration("pay", targetNs);

        // Add WS-Security header with timestamp
        addSecurityTimestamp(envelope);

        // Create SOAP body
        SOAPBody body = envelope.getBody();
        SOAPElement processPayment = body.addChildElement("processPayment", "pay", targetNs);

        processPayment.addChildElement("transactionId", "pay").addTextNode(txnId);
        processPayment.addChildElement("cardNumber", "pay").addTextNode(cardNumber);
        processPayment.addChildElement("cardHolder", "pay").addTextNode(cardHolder);
        processPayment.addChildElement("amount", "pay").addTextNode(String.valueOf(amount));
        processPayment.addChildElement("currency", "pay").addTextNode(currency);
        processPayment.addChildElement("merchantId", "pay").addTextNode(merchantId);
        processPayment.addChildElement("description", "pay").addTextNode(description);

        soapMessage.saveChanges();

        System.out.println("[Client] Sending payment request:");
        soapMessage.writeTo(System.out);
        System.out.println();

        return soapMessage;
    }

    private static SOAPMessage createStatusCheckSOAPRequest(String txnId) throws Exception {
        MessageFactory messageFactory = MessageFactory.newInstance();
        SOAPMessage soapMessage = messageFactory.createMessage();
        SOAPPart soapPart = soapMessage.getSOAPPart();
        SOAPEnvelope envelope = soapPart.getEnvelope();

        String targetNs = "http://gateway.payment.com/ws";
        envelope.addNamespaceDeclaration("pay", targetNs);

        addSecurityTimestamp(envelope);

        SOAPBody body = envelope.getBody();
        SOAPElement statusCheck = body.addChildElement("checkTransactionStatus", "pay", targetNs);
        statusCheck.addChildElement("transactionId", "pay").addTextNode(txnId);

        soapMessage.saveChanges();
        return soapMessage;
    }

